struct BitArray{

    uint64_t n;

    static const uint64_t b = 64;

    static const uint64_t l = 512;

    static const uint64_t s = 64;

    static const uint64_t MASK = (1LLU<<63)-1 + (1LLU<<63);



    vector<uint64_t> B;

    vector<uint64_t> L, S;



    BitArray() {}

    BitArray(vector<bool>& a){

        uint64_t sz = a.size();

        uint64_t szB,szL,szS;

        szB = (sz + b-1) / b;

        szL = (sz + l-1) / l;

        szS = l/s*szL;



        B.assign(szB,0);

        L.assign(szL,0);

        S.assign(szS,0);



        for(uint64_t i=0; i<sz; ++i){

            if(!a[i]) continue;

